INSERT INTO `his_config_info` VALUES (5, 35, 'chat-modules-dev.yml', 'DEFAULT_GROUP', '', '# spring配置\nspring:\n  datasource:\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://chat.dilicili.cn:3306/chat-test?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&&allowPublicKeyRetrieval=true\n    username: root\n    password: 5217758\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: admin\n        loginPassword: 123456\n    dynamic:\n      druid:\n        initial-size: 5\n        min-idle: 5\n        maxActive: 20\n        maxWait: 60000\n        timeBetweenEvictionRunsMillis: 60000\n        minEvictableIdleTimeMillis: 300000\n        validationQuery: SELECT 1 FROM DUAL\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        filters: stat,slf4j\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.wangscaler\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# swagger配置\nswagger:\n  title: 系统模块接口文档\n  license: Powered By WangScaler\n  licenseUrl: https://blog.dilicili.cn', 'ec94d43e075d20a0041d979ff574d0b2', '2023-02-03 11:32:55', '2023-02-03 11:32:29', 'nacos', '172.17.0.1', 'U', '', NULL);
INSERT INTO `his_config_info` VALUES (0, 36, 'sentinel-grade-gateway', 'DEFAULT_GROUP', '', '[\r\n	  {\r\n	       \"resource\":\"/chat-user\",\r\n	       \"count\":200, \r\n	       \"grade\":0,\r\n	       \"timeWindow\":5\r\n	   },\r\n       {\r\n	       \"resource\":\"/chat-room\",\r\n	       \"count\":200, \r\n	       \"grade\":0,\r\n	       \"timeWindow\":5\r\n	   }\r\n \r\n]', 'b6ad27475ab2c2d060fd120f027dcade', '2023-02-03 14:33:48', '2023-02-03 14:33:23', NULL, '172.17.0.1', 'I', '', NULL);
INSERT INTO `his_config_info` VALUES (2, 37, 'chat-gateway-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n  cloud:\n    gateway:\n      globalcors:\n        add-to-simple-url-handler-mapping: true #解决OPTION被拦截的问题\n        cors-configurations:\n          \'[/**]\':\n            allowedOrigins: # 允许哪些网站的跨域请求\n              - \"http://blog.dilicili.cn\"\n              - \"http://chat.dilicili.cn\"\n            allowedMethods: #允许的请求方式\n              - \"GET\"\n              - \"POST\"\n              - \"DELETE\"\n              - \"PUT\"\n              - \"OPTIONS\"\n            allowedHeaders: \"*\" #允许在请求中携带头信息\n            allowedCredentials: true #是否允许携带cookie\n            maxAge: 360000 #跨越的有效期\n      routes:\n        - id: chat-user #路由标识\n          uri: lb://chat-user #路由的目标地址\n          predicates:\n            - Path=/user/** # 路径断言\n        - id: chat-room #路由标识\n          uri: lb://chat-room #路由的目标地址\n          predicates:\n              - Path=/room/** # 路径断言\n# 安全配置\nsecurity:\n  # 验证码\n  captcha:\n    enabled: true\n    type: math\n  # 防止XSS攻击\n  xss:\n    enabled: true\n    excludeUrls:\n      - /system/notice\n  # 不校验白名单\n  ignore:\n    whites:\n      - /auth/logout\n      - /auth/login\n      - /auth/register\n      - /*/v2/api-docs\n      - /csrf\n', 'a7327f02262e2f3ab37831584d40253c', '2023-02-03 15:25:26', '2023-02-03 15:25:00', 'nacos', '172.17.0.1', 'U', '', NULL);
INSERT INTO `his_config_info` VALUES (5, 38, 'chat-modules-dev.yml', 'DEFAULT_GROUP', '', '# spring配置\nspring:\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n  datasource:\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://chat.dilicili.cn:3306/chat-test?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&&allowPublicKeyRetrieval=true\n    username: root\n    password: 5217758\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: admin\n        loginPassword: 123456\n    dynamic:\n      druid:\n        initial-size: 5\n        min-idle: 5\n        maxActive: 20\n        maxWait: 60000\n        timeBetweenEvictionRunsMillis: 60000\n        minEvictableIdleTimeMillis: 300000\n        validationQuery: SELECT 1 FROM DUAL\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        filters: stat,slf4j\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.wangscaler\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# swagger配置\nswagger:\n  title: 系统模块接口文档\n  license: Powered By WangScaler\n  licenseUrl: https://blog.dilicili.cn', '085885c75e6bbb4fb54375e416e1ec64', '2023-02-03 16:18:21', '2023-02-03 16:17:55', 'nacos', '172.17.0.1', 'U', '', NULL);
INSERT INTO `his_config_info` VALUES (1, 39, 'application-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n\n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n  okhttp:\n    enabled: true\n  httpclient:\n    enabled: false\n  client:\n    config:\n      default:\n        connectTimeout: 10000\n        readTimeout: 10000\n  compression:\n    request:\n      enabled: true\n    response:\n      enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \'*\'\n', 'aaa73b809cfd4d0058893aa13da57806', '2023-02-03 16:19:36', '2023-02-03 16:19:11', 'nacos', '172.17.0.1', 'U', '', NULL);
