INSERT INTO `his_config_info` VALUES (5, 50, 'chat-modules-dev.yml', 'DEFAULT_GROUP', '', '# spring配置\nspring:\n  datasource:\n    master:\n      driver-class-name: com.mysql.cj.jdbc.Driver\n      url: jdbc:mysql://chat.dilicili.cn:3306/chat-test?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&&allowPublicKeyRetrieval=true\n      username: root\n      password: 5217758\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: admin\n        loginPassword: 123456\n    dynamic:\n      druid:\n        initial-size: 5\n        min-idle: 5\n        maxActive: 20\n        maxWait: 60000\n        timeBetweenEvictionRunsMillis: 60000\n        minEvictableIdleTimeMillis: 300000\n        validationQuery: SELECT 1 FROM DUAL\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        filters: stat,slf4j\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.wangscaler\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# swagger配置\nswagger:\n  title: 系统模块接口文档\n  license: Powered By WangScaler\n  licenseUrl: https://blog.dilicili.cn', '35ac8fec7bb4abfdf9c2200b77e62de0', '2023-02-10 15:57:23', '2023-02-10 15:56:57', 'nacos', '172.17.0.1', 'U', '', NULL);
INSERT INTO `his_config_info` VALUES (1, 51, 'application-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n  okhttp:\n    enabled: true\n  httpclient:\n    enabled: false\n  client:\n    config:\n      default:\n        connectTimeout: 10000\n        readTimeout: 10000\n  compression:\n    request:\n      enabled: true\n    response:\n      enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \'*\'\n', '99606ddcd2086283210f67828602be43', '2023-02-10 16:08:35', '2023-02-10 16:08:09', 'nacos', '172.17.0.1', 'U', '', NULL);
INSERT INTO `his_config_info` VALUES (2, 52, 'chat-gateway-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n  cloud:\n    gateway:\n      globalcors:\n        add-to-simple-url-handler-mapping: true #解决OPTION被拦截的问题\n        cors-configurations:\n          \'[/**]\':\n            allowedOrigins: # 允许哪些网站的跨域请求\n              - \"http://blog.dilicili.cn\"\n              - \"http://chat.dilicili.cn\"\n            allowedMethods: #允许的请求方式\n              - \"GET\"\n              - \"POST\"\n              - \"DELETE\"\n              - \"PUT\"\n              - \"OPTIONS\"\n            allowedHeaders: \"*\" #允许在请求中携带头信息\n            allowedCredentials: true #是否允许携带cookie\n            maxAge: 360000 #跨越的有效期\n      discovery:\n        locator:\n          lowerCaseServiceId: true\n          enabled: true\n      routes:\n        - id: chat-user #路由标识\n          uri: lb://chat-user #路由的目标地址\n          predicates:\n            - Path=/user/** # 路径断言\n        - id: chat-room #路由标识\n          uri: lb://chat-room #路由的目标地址\n          predicates:\n              - Path=/room/** # 路径断言\n# 安全配置\nsecurity:\n  # 不校验白名单\n  ignore:\n    whites:\n      - /*/v2/api-docs\n      - /csrf', 'e69e0712328520b7550f3228e33c94ff', '2023-02-10 16:10:20', '2023-02-10 16:09:55', 'nacos', '172.17.0.1', 'U', '', NULL);
INSERT INTO `his_config_info` VALUES (5, 53, 'chat-modules-dev.yml', 'DEFAULT_GROUP', '', '# spring配置\nspring:\n  datasource:\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: admin\n        loginPassword: 123456\n    dynamic:\n      druid:\n        initial-size: 5\n        min-idle: 5\n        maxActive: 20\n        maxWait: 60000\n        timeBetweenEvictionRunsMillis: 60000\n        minEvictableIdleTimeMillis: 300000\n        validationQuery: SELECT 1 FROM DUAL\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        filters: stat,slf4j\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n      master:\n        driver-class-name: com.mysql.cj.jdbc.Driver\n        url: jdbc:mysql://chat.dilicili.cn:3306/chat-test?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&&allowPublicKeyRetrieval=true\n        username: root\n        password: 5217758\n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.wangscaler\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# swagger配置\nswagger:\n  title: 系统模块接口文档\n  license: Powered By WangScaler\n  licenseUrl: https://blog.dilicili.cn', 'c8aa87a721869cbb4480bd961946fa67', '2023-02-10 16:12:15', '2023-02-10 16:11:50', 'nacos', '172.17.0.1', 'U', '', NULL);
INSERT INTO `his_config_info` VALUES (0, 54, 'seataServer.properties', 'DEFAULT_GROUP', '', '# 数据存储方式\r\nstore.mode=db\r\nstore.db.datasource=druid\r\nstore.db.dbType=mysql\r\nstore.db.driverClassName=com.mysql.jdbc.Driver\r\nstore.db.url=jdbc:mysql://chat.dilicili.cn:3306/seata?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&&allowPublicKeyRetrieval=true\r\nstore.db.user=root\r\nstore.db.password=5217758\r\nstore.db.minConn=5\r\nstore.db.maxConn=30\r\nstore.db.globalTable=global_table\r\nstore.db.branchTable=branch_table\r\nstore.db.queryLimit=100\r\nstore.db.lockTable=lock_table\r\nstore.db.maxWait=5000\r\n## 事务日志配置\r\nserver.recovery.committingRetryPeriod=1000\r\nserver.recovery.asynCommittingRetryPeriod=1000\r\nserver.recovery.rollbackingRetryPeriod=1000\r\nserver.recovery.timeoutRetryPeriod=1000\r\nserver.maxCommitRetryTimeout=1\r\nserver.maxRollbackRetryTimeout=1\r\nserver.rollbackRetryTimeoutUnlockEnable=false\r\nserver.undo.logSaveDays=7\r\nserver.undo.logDeletePeriod=86400000\r\n## 客户端与服务端传输方式\r\ntransport.serialization=seata\r\ntransport.compressor=none\r\n# 关闭metrics功能,提高性能\r\nmetrics.enable=false\r\nmetrics.registryType=compact\r\nmetrics.exporterList=prometheus\r\nmetrics.exporterPrometheusPort=9898', 'ae47eea12dea281d402765f141ce3a8f', '2023-02-11 10:07:05', '2023-02-11 10:06:39', NULL, '172.17.0.1', 'I', '', NULL);
INSERT INTO `his_config_info` VALUES (1, 55, 'application-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n# 兼容swagger3和springboot2.6\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n  okhttp:\n    enabled: true\n  httpclient:\n    enabled: false\n  client:\n    config:\n      default:\n        connectTimeout: 10000\n        readTimeout: 10000\n  compression:\n    request:\n      enabled: true\n    response:\n      enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \'*\'\n', '95d21aa90795396f8784cd26c46a7a34', '2023-02-11 11:28:22', '2023-02-11 11:27:55', 'nacos', '172.17.0.1', 'U', '', NULL);
INSERT INTO `his_config_info` VALUES (2, 56, 'chat-gateway-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n  cloud:\n    gateway:\n      globalcors:\n        add-to-simple-url-handler-mapping: true #解决OPTION被拦截的问题\n        cors-configurations:\n          \'[/**]\':\n            allowedOrigins: # 允许哪些网站的跨域请求\n              - \"http://blog.dilicili.cn\"\n              - \"http://chat.dilicili.cn\"\n            allowedMethods: #允许的请求方式\n              - \"GET\"\n              - \"POST\"\n              - \"DELETE\"\n              - \"PUT\"\n              - \"OPTIONS\"\n            allowedHeaders: \"*\" #允许在请求中携带头信息\n            allowedCredentials: true #是否允许携带cookie\n            maxAge: 360000 #跨越的有效期\n      discovery:\n        locator:\n          lowerCaseServiceId: true\n          enabled: true\n      routes:\n        - id: chat-user #路由标识\n          uri: lb://chat-user #路由的目标地址\n          predicates:\n            - Path=/user/** # 路径断言\n          filters:\n            - StripPrefix=1\n        - id: chat-room #路由标识\n          uri: lb://chat-room #路由的目标地址\n          predicates:\n              - Path=/room/** # 路径断言\n          filters:\n            - StripPrefix=1\n# 安全配置\nsecurity:\n  # 不校验白名单\n  ignore:\n    whites:\n      - /*/v2/api-docs\n      - /csrf', 'dce5b9e4c63d4004816d3a07d91c1747', '2023-02-11 14:41:01', '2023-02-11 14:40:35', 'nacos', '172.17.0.1', 'U', '', NULL);
