INSERT INTO `his_config_info` VALUES (1, 82, 'application-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n# 兼容swagger3和springboot2.6\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n# feign 配置\nfeign:\n  hystrix:\n    enabled: true\n  sentinel:\n    enabled: true\n  okhttp:\n    enabled: true\n  httpclient:\n    enabled: false\n  client:\n    config:\n      default:\n        connectTimeout: 10000\n        readTimeout: 10000\n  compression:\n    request:\n      enabled: true\n    response:\n      enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \'*\'\nseata:\n  data-source-proxy-mode: XA\n  registry:\n    type: nacos\n    nacos:\n      server-addr: 127.0.0.1:8848\n      namespace: \"\"\n      group: DEFAULT_GROUP\n      application: seata-server\n  tx-service-group: seata-modules\n  service:\n    vgroup-mapping:\n      seata-modules: DEFAULT\n\n', 'a1f32454ed0325794c4aba404fb76f66', '2023-02-13 14:10:02', '2023-02-13 14:09:37', 'nacos', '172.17.0.1', 'U', '', NULL);
