INSERT INTO `his_config_info` VALUES (0, 88, 'seataServer.properties', 'SEATA_GROUP', '', '#tx_group：自定义名字，很重要，与项目配置文件的tx-service-group一一对应\r\nservice.vgroupMapping.tx_group=seata-modules\r\n#seata的ip+端口\r\nservice.default.grouplist=192.168.1.31:8091\r\n \r\n# 修改存储模式为数据库存储\r\nstore.mode=db\r\n# 指定数据库为mysql，其他数据库类型根据自身情况修改\r\nstore.db.dbType=mysql\r\n# 指定引擎，mysql8以下为com.mysql.jdbc.Driver，mysql8为com.mysql.cj.jdbc.Driver\r\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\r\nstore.db.url=jdbc:mysql://192.168.1.31:3306/seata?useUnicode=true\r\nstore.db.user=root\r\nstore.db.password=5217758', 'c820ae10128000ada8564fb74ffd9cc0', '2023-02-13 16:30:20', '2023-02-13 16:29:55', NULL, '172.17.0.1', 'I', '', NULL);
INSERT INTO `his_config_info` VALUES (1, 89, 'application-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n# 兼容swagger3和springboot2.6\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n# feign 配置\nfeign:\n  hystrix:\n    enabled: true\n  sentinel:\n    enabled: true\n  okhttp:\n    enabled: true\n  httpclient:\n    enabled: false\n  client:\n    config:\n      default:\n        connectTimeout: 10000\n        readTimeout: 10000\n  compression:\n    request:\n      enabled: true\n    response:\n      enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \'*\'\nseata:\n  data-source-proxy-mode: XA\n  registry:\n    type: nacos\n    nacos:\n      server-addr: 192.168.1.31:8848\n      namespace: \"\"\n      group: DEFAULT_GROUP\n      application: seata-server\n  tx-service-group: seata-modules\n  service:\n    vgroup-mapping:\n      seata-modules: DEFAULT\n\n', '41337c9a73742d11516c200b70a5a61d', '2023-02-13 17:01:00', '2023-02-13 17:00:35', 'nacos', '172.17.0.1', 'U', '', NULL);
INSERT INTO `his_config_info` VALUES (86, 90, 'seataServer.properties', 'SEATA_GROUP', '', '#tx_group：自定义名字，很重要，与项目配置文件的tx-service-group一一对应\r\nservice.vgroupMapping.tx_group=seata-modules\r\n#seata的ip+端口\r\nservice.default.grouplist=192.168.1.31:8091\r\n \r\n# 修改存储模式为数据库存储\r\nstore.mode=db\r\n# 指定数据库为mysql，其他数据库类型根据自身情况修改\r\nstore.db.dbType=mysql\r\n# 指定引擎，mysql8以下为com.mysql.jdbc.Driver，mysql8为com.mysql.cj.jdbc.Driver\r\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\r\nstore.db.url=jdbc:mysql://192.168.1.31:3306/seata?useUnicode=true\r\nstore.db.user=root\r\nstore.db.password=5217758', 'c820ae10128000ada8564fb74ffd9cc0', '2023-02-13 17:04:39', '2023-02-13 17:04:14', NULL, '172.17.0.1', 'D', '', NULL);
INSERT INTO `his_config_info` VALUES (0, 91, 'seata-server.yml', 'SEATA_GROUP', '', 'service:\r\n	#需要修改为自己的group，与客户端相对应，目前先这样\r\n    vgroupMapping:\r\n        netty-seata-test-group: seata-modules\r\n        netty-system-platform-group: seata-modules\r\n        netty-mybatis-plus-test-group: seata-modules\r\n    default:\r\n        grouplist: 192.168.1.31:8091\r\n    enableDegrade: false\r\n    disableGlobalTransaction: false\r\n\r\nclient:\r\n    rm:\r\n        asyncCommitBufferLimit: 10000\r\n        lock:\r\n            retryInterval: 10\r\n            retryTimes: 30\r\n            retryPolicyBranchRollbackOnConflict: true\r\n        reportRetryCount: 5\r\n        tableMetaCheckEnable: true\r\n        tableMetaCheckerInterval: 60000\r\n        sqlParserType: druid\r\n        reportSuccessEnable: false\r\n        sagaBranchRegisterEnable: false\r\n        sagaJsonParser: fastjson\r\n        tccActionInterceptorOrder: -2147482648\r\n    tm:\r\n        commitRetryCount: 5\r\n        rollbackRetryCount: 5\r\n        defaultGlobalTransactionTimeout: 60000\r\n        degradeCheck: false\r\n        degradeCheckAllowTimes: 10\r\n        degradeCheckPeriod: 2000\r\n        interceptorOrder: -2147482648\r\n    undo:\r\n        dataValidation: true\r\n        logSerialization: jackson\r\n        onlyCareUpdateColumns: true\r\n        logTable: undo_log\r\n        compress:\r\n            enable: true\r\n            type: zip\r\n            threshold: 64k\r\nserver:\r\n    undo:\r\n        logSaveDays: 7\r\n        logDeletePeriod: 86400000\r\n    recovery:\r\n        committingRetryPeriod: 1000\r\n        asynCommittingRetryPeriod: 1000\r\n        rollbackingRetryPeriod: 1000\r\n        timeoutRetryPeriod: 1000\r\n    maxCommitRetryTimeout: -1\r\n    maxRollbackRetryTimeout: -1\r\n    rollbackRetryTimeoutUnlockEnable: false\r\n    distributedLockExpireTime: 10000\r\n    xaerNotaRetryTimeout: 60000\r\n    session:\r\n        branchAsyncQueueSize: 5000\r\n        enableBranc