INSERT INTO `his_config_info` VALUES (5, 106, 'chat-modules-dev.yml', 'DEFAULT_GROUP', '', '# spring配置\nspring:\n  datasource:\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: admin\n        loginPassword: 123456\n    dynamic:\n      druid:\n        initial-size: 5\n        min-idle: 5\n        maxActive: 20\n        maxWait: 60000\n        timeBetweenEvictionRunsMillis: 60000\n        minEvictableIdleTimeMillis: 300000\n        validationQuery: SELECT 1 FROM DUAL\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        filters: stat,slf4j\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n      datasource:\n        master:\n          driver-class-name: com.mysql.cj.jdbc.Driver\n          url: jdbc:mysql://192.168.1.31:3306/chat-test?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&&allowPublicKeyRetrieval=true\n          username: root\n          password: 5217758\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.wangscaler\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# swagger配置\nswagger:\n  title: 系统模块接口文档\n  license: Powered By WangScaler\n  licenseUrl: https://blog.dilicili.cn', 'd41439e4441c137a730db6ac6c93cae3', '2023-02-15 09:50:19', '2023-02-15 09:49:52', 'nacos', '172.17.0.1', 'U', '', NULL);
